namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            MakeNotification("Welcome to the notifications demo!"),
            MakeNotification("Your profile was updated successfully."),
            MakeNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Id > lastSeenId).ToList());
        }
    }

    /// <summary>Simulates an external event by adding a random notification.</summary>
    public void SimulateIncoming()
    {
        string[] templates =
        [
            "Server health check passed.",
            "Deployment completed for service-api.",
            "Disk usage alert cleared.",
            "New user signed up.",
            "Backup finished successfully.",
            "CI pipeline #{{id}} succeeded.",
        ];

        lock (_lock)
        {
            var msg = templates[Random.Shared.Next(templates.Length)]
                .Replace("{{id}}", Random.Shared.Next(1000, 9999).ToString());
            _notifications.Add(MakeNotification(msg));
        }
    }

    private Notification MakeNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    // Persisted across prerender → interactive so initial data isn't fetched twice.
    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures the fetch only happens during prerender;
        // on interactive activation the persisted snapshot is reused.
        PersistedNotifications ??= await NotificationService.GetNotificationsAsync();
        notifications = PersistedNotifications;
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender, so this is
            // the safe place to start background work for the interactive page.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate an external system occasionally producing notifications.
                NotificationService.SimulateIncoming();

                var newer = await NotificationService.GetNotificationsSinceAsync(_lastSeenId);
                if (newer.Count > 0)
                {
                    notifications.AddRange(newer);
                    _lastSeenId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on dispose — exit cleanly.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

